INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9fd41731-6785-475c-9e8d-4b9148e7505d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jupyter Data Profiling — One Cell to Understand Any Dataset$escape$,
  $escape$Every exploration starts the same: shape, dtypes, nulls, distributions. In Jupyter, you can collapse this entire ritual into a single rich-output cell using ydata-profiling (formerly pandas-profiling). Install with `pip install ydata-profiling` and generate an interactive HTML report inline. The report renders directly in your notebook output cell — histograms, correlation matrices, missing-value heatmaps, duplicate row counts, and type warnings — all without writing plotting code. For large datasets, use `minimal=True` to skip expensive computations like correlations and text analysis. You can also call `profile.to_widgets()` instead of `to_notebook_iframe()` to get an ipywidgets-based interactive view that plays nicer with JupyterLab's rendering engine. Export reports via `profile.to_file("report.html")` to share with teammates who don't run notebooks. Combine this with `df.describe().T` in a preceding cell for a quick numeric sanity check before the full profile generates. This workflow turns a 20-minute manual EDA into a single Shift+Enter.$escape$,
  $escape$import pandas as pd
from ydata_profiling import ProfileReport

df = pd.read_csv("dataset.csv")

# Quick sanity check
df.describe().T

# Full interactive profile in-cell
profile = ProfileReport(df, title="Dataset Profile", minimal=True)
profile.to_notebook_iframe()

# Export for sharing
profile.to_file("profile_report.html")$escape$,
  $escape$python$escape$,
