INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e01b5e5c-b69f-4e5b-b7a4-589404b5f858',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jupyter + NumPy — Visualize Broadcasting and Vectorization Speedups in Your Notebook$escape$,
  $escape$Jupyter's `%%timeit` cell magic is the fastest way to prove why NumPy vectorization destroys Python loops. Broadcasting lets you operate on arrays of different shapes without copying data — but the performance difference is invisible until you measure it in a notebook cell.

Key insights for your Jupyter workflow:

**Memory layout matters.** NumPy defaults to C-contiguous (row-major) arrays. Column-wise operations on C-order arrays thrash cache. Use `np.asfortranarray()` when your workload is column-heavy, then verify with `arr.flags` right in a cell.

**Broadcasting rules:** dimensions align from the right. Shape `(3,1)` broadcasts with `(1,4)` to produce `(3,4)` — no explicit `np.tile()` needed.

**Always benchmark in-place.** Jupyter's `%timeit` runs multiple loops automatically, giving stable measurements. Compare vectorized ops against `for` loops on the same array to build intuition about 10–100× speedups. Use `%%timeit -n 1000` for fine-grained control over iteration count.$escape$,
  $escape$import numpy as np

# --- Cell 1: Broadcasting demo ---
a = np.arange(3).reshape(3, 1)  # shape (3,1)
b = np.arange(4).reshape(1, 4)  # shape (1,4)
result = a * b  # broadcasts to (3,4)
print(f"Shapes: {a.shape} * {b.shape} -> {result.shape}")
print(result)

# --- Cell 2: Vectorization vs loop (use %%timeit in real notebook) ---
arr = np.random.randn(1_000_000)
%timeit arr ** 2 + 2 * arr + 1          # vectorized: ~2ms
%timeit np.array([x**2 + 2*x + 1 for x in arr])  # loop: ~800ms

# --- Cell 3: Check memory layout ---
print(arr.flags['C_CONTIGUOUS'])  # True by default$escape$,
  $escape$python$escape$,
