INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c6448d26-c746-4656-915c-e9bae10ecb75',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jupyter Notebooks — Interactive Data Cleaning Pipeline with Cell-by-Cell Validation$escape$,
  $escape$Jupyter's cell-based execution model is ideal for data cleaning because you can inspect results at every stage. The pattern: one cleaning operation per cell, always display shape and sample output below. Start by profiling nulls with `df.isnull().sum()` in its own cell — Jupyter renders the Series as a formatted table automatically. For outlier detection, use a cell to compute IQR bounds and a follow-up cell with a histogram via `df[col].hist()` — inline plots (`%matplotlib inline`) let you visually confirm before filtering. Type coercion is where Jupyter shines: run `df.dtypes` in one cell, apply `pd.to_numeric(df[col], errors='coerce')` in the next, then re-check dtypes immediately. Coerced values become NaN, visible in the same notebook flow. For deduplication, display `df.duplicated().sum()` before and after `df.drop_duplicates()` in adjacent cells. Use `%%time` cell magic on expensive operations to catch slow cleaning steps. This inspect-transform-verify loop per cell is what makes Jupyter the natural environment for data cleaning — every intermediate state is visible and reproducible.$escape$,
  $escape$# Cell 1: Profile nulls
print(f"Shape: {df.shape}")
df.isnull().sum().sort_values(ascending=False)

# Cell 2: Detect outliers via IQR
%matplotlib inline
Q1, Q3 = df['value'].quantile([0.25, 0.75])
IQR = Q3 - Q1
mask = df['value'].between(Q1 - 1.5*IQR, Q3 + 1.5*IQR)
print(f"Outliers removed: {(~mask).sum()}")
df = df[mask]

# Cell 3: Coerce types and deduplicate
df['price'] = pd.to_numeric(df['price'], errors='coerce')
df = df.drop_duplicates()
%%time
df.info()$escape$,
  $escape$python$escape$,
