INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4ccb0528-dc54-4448-9a33-fe8d9b14cae8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jupyter EDA Toolkit — Correlation Heatmaps, Pivot Tables & GroupBy in One Notebook$escape$,
  $escape$Jupyter's cell-based execution makes iterative EDA fast — run a correlation matrix, tweak the visualization, re-run just that cell. The key pattern: keep data loading in cell 1, transformations in cell 2, and visualizations in cell 3+. This lets you modify aggregation logic without reloading data.

For correlation analysis, `df.corr()` paired with Seaborn's `heatmap()` renders inline thanks to `%matplotlib inline`. Use `display()` instead of `print()` for DataFrames — Jupyter's rich display renders styled HTML tables with automatic truncation.

Pivot tables via `pd.pivot_table()` with `aggfunc=['mean','count']` give you multi-metric summaries. Chain `.style.background_gradient()` to get conditional formatting directly in the notebook output — no export needed.

For grouped aggregations, `df.groupby().agg()` with named aggregations keeps output readable. Pro tip: use `%%time` cell magic to benchmark heavy groupby operations, and `df.memory_usage(deep=True)` in a separate cell to watch memory before scaling up.$escape$,
  $escape$%matplotlib inline
import pandas as pd, seaborn as sns, matplotlib.pyplot as plt

df = pd.read_csv("data.csv")

# Cell 2: Correlation heatmap
corr = df.select_dtypes("number").corr()
sns.heatmap(corr, annot=True, fmt=".2f", cmap="coolwarm", center=0)
plt.title("Feature Correlations")
plt.tight_layout()

# Cell 3: Pivot table with styled output
pivot = pd.pivot_table(df, values="revenue", index="region",
                       columns="quarter", aggfunc=["mean", "count"])
display(pivot.style.background_gradient(cmap="YlGn"))$escape$,
  $escape$python$escape$,
