INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c55d1d20-4c29-4f6e-bcbd-7274a20d3f4d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jupyter Matplotlib — Publication-Quality Charts with the Figure/Axes API$escape$,
  $escape$The pyplot shortcut (`plt.plot()`) breaks down fast in Jupyter notebooks when you need multi-panel figures or fine-grained control. Switch to the explicit Figure/Axes API: `fig, axes = plt.subplots()` gives you direct handles to every element.

In Jupyter, pair this with `%matplotlib inline` or `%matplotlib widget` (for interactive zoom/pan via ipympl). The widget backend is especially powerful — resize and inspect figures live without re-running cells.

For publication quality, control the figure at creation: set `figsize`, `dpi`, and `constrained_layout=True` to avoid overlapping labels. Style individual axes via `ax.set_xlabel()`, `ax.tick_params()`, and `ax.spines` — never rely on global `plt.rcParams` mid-notebook, as it silently mutates state across cells.

Use `fig.savefig('plot.pdf', bbox_inches='tight')` from the same cell as your plot — Jupyter's inline backend closes figures after cell execution, so saving in a later cell produces blank output. Subplots share axes with `sharey=True` to declutter repeated labels.$escape$,
  $escape$%matplotlib inline
import matplotlib.pyplot as plt
import numpy as np

x = np.linspace(0, 2 * np.pi, 200)
fig, (ax1, ax2) = plt.subplots(1, 2, figsize=(10, 4),
                                sharey=True, constrained_layout=True, dpi=150)
ax1.plot(x, np.sin(x), color='#2563eb', linewidth=2)
ax1.set_title('Sine'); ax1.set_xlabel('Radians'); ax1.set_ylabel('Amplitude')
ax2.plot(x, np.cos(x), color='#dc2626', linewidth=2)
ax2.set_title('Cosine'); ax2.set_xlabel('Radians')
for ax in (ax1, ax2):
    ax.spines[['top', 'right']].set_visible(False)
fig.savefig('trig_plots.pdf', bbox_inches='tight')$escape$,
  $escape$python$escape$,
