INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7c168ae0-6b2b-42c9-bbf9-ccbda38e9778',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jupyter + Seaborn — Inline Statistical Plots That Just Work with Pandas$escape$,
  $escape$Seaborn is built on matplotlib but designed for Pandas DataFrames, making it the fastest path from raw data to publication-quality statistical plots inside Jupyter. The magic starts with `%matplotlib inline` — every Seaborn call renders directly below the cell, no `plt.show()` needed.

Seaborn's `set_theme()` instantly upgrades your entire notebook's visual style. Call it once in your first cell and every subsequent plot inherits clean aesthetics. For EDA, `sns.pairplot(df)` generates a full correlation matrix of scatterplots in one line — something that would take dozens of matplotlib calls.

The real power is statistical integration. Functions like `sns.lmplot()` and `sns.boxenplot()` compute regressions and distributions on the fly. Pass a DataFrame column name as `hue` to split by category automatically. Seaborn reads your DataFrame's dtypes and adjusts axis formatting.

Pro tip: use `sns.set_context('notebook')` specifically — it optimizes font sizes and line weights for Jupyter's rendered cell output width, not slides or papers.$escape$,
  $escape$# First cell — run once
%matplotlib inline
import seaborn as sns
import pandas as pd

sns.set_theme(style="whitegrid")
sns.set_context("notebook")

# Load and plot in one cell
df = sns.load_dataset("penguins").dropna()
sns.pairplot(df, hue="species", height=2.5)

# Next cell — regression with confidence interval
sns.lmplot(data=df, x="flipper_length_mm", y="body_mass_g",
           hue="species", height=5, aspect=1.4)$escape$,
  $escape$python$escape$,
