INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd1c08be0-65a1-4e1c-b799-36e7effcb8b0',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jupyter %%timeit and Chunked DataFrames — Process Million-Row CSVs Without Crashing Your Kernel$escape$,
  $escape$Jupyter kernels share a single memory pool across all cells. Loading a 2GB CSV with pd.read_csv() in one shot often triggers a MemoryError or kills the kernel silently. The fix: use the chunksize parameter to stream data in batches, processing each chunk with vectorized NumPy/Pandas ops instead of Python loops.

Wrap your pipeline in %%timeit to benchmark cell execution directly in-notebook. Combine this with %memit (from memory_profiler) to track per-cell memory deltas — critical when your kernel's RAM is capped by your machine or a JupyterHub resource limit.

Key patterns: replace iterrows() with .apply() or direct column arithmetic (true vectorization). Use df.astype('category') for repeated string columns — this alone can cut memory 80%. For exploratory work, load only needed columns via usecols. Always call del df and gc.collect() in cleanup cells to release memory before the next pipeline stage. Monitor with !jupyter kernelspec list to verify you're on the right env.$escape$,
  $escape$%load_ext memory_profiler

import pandas as pd
import gc

# Stream large CSV in 50k-row chunks
results = []
for chunk in pd.read_csv('events.csv', chunksize=50_000, usecols=['ts', 'value', 'category']):
    chunk['category'] = chunk['category'].astype('category')
    chunk['value_norm'] = (chunk['value'] - chunk['value'].mean()) / chunk['value'].std()
    results.append(chunk.groupby('category')['value_norm'].mean())

summary = pd.concat(results).groupby(level=0).mean()
del results; gc.collect()  # free memory for next cell
summary$escape$,
  $escape$python$escape$,
