INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5e4d20aa-183c-46d1-a1af-a774887cf77c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jupyter Time Series Toolkit — Resampling, Rolling Windows & Lag Features in One Notebook$escape$,
  $escape$Jupyter's cell-by-cell execution makes it ideal for iterative time series exploration. Start by resampling raw timestamps to uniform intervals using pandas' `.resample()` — visualize the before/after inline with `%matplotlib inline` to catch gaps immediately. Next, apply `.rolling()` windows to smooth noise; Jupyter lets you tweak window sizes and re-execute the cell to visually compare 7-day vs 30-day moving averages without rerunning your entire pipeline. For lag features, use `.shift()` to create autoregressive inputs — display the correlation matrix with `df.corr()` right below to validate signal strength interactively. Seasonality detection benefits from Jupyter's rich output: plot `seasonal_decompose()` results from statsmodels, which renders the trend, seasonal, and residual components as a multi-panel figure directly in the notebook. Pro tip: use `%%time` cell magic to benchmark your feature engineering steps, and `display(df.head())` between transforms to catch shape mismatches early. This inspect-as-you-go workflow is what makes Jupyter unbeatable for time series EDA.$escape$,
  $escape$import pandas as pd
from statsmodels.tsa.seasonal import seasonal_decompose
%matplotlib inline

df = pd.read_csv('sensor_data.csv', parse_dates=['timestamp'], index_col='timestamp')
df_hourly = df['value'].resample('1h').mean().interpolate()

df_hourly.rolling(window=24).mean().plot(title='24h Rolling Mean')

df_feat = df_hourly.to_frame()
df_feat['lag_1'] = df_feat['value'].shift(1)
df_feat['lag_24'] = df_feat['value'].shift(24)

result = seasonal_decompose(df_hourly, period=24)
result.plot();$escape$,
  $escape$python$escape$,
