INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '25c5a40c-8d0e-4967-894d-f5f2a7bc3037',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jupyter Notebooks for Statistical Testing — Interactive Hypothesis Testing Done Right$escape$,
  $escape$Jupyter's cell-based execution model is ideal for statistical testing workflows: state a hypothesis in a markdown cell, run the test in code, then interpret results inline — all in one reproducible document. Use `scipy.stats` for hypothesis tests and render results directly beneath your analysis. A common pitfall: running multiple t-tests across cells without correction inflates false positives. Use `statsmodels.stats.multitest` for Bonferroni or FDR correction. For confidence intervals, `scipy.stats.t.interval()` gives you exact intervals you can display with `IPython.display.Markdown` for formatted output. Pro tip: leverage Jupyter's `%store` magic to persist test results across notebooks when comparing experiments. Structure your notebook as: (1) markdown cell with H₀/H₁, (2) data loading cell, (3) assumption checks (normality via `shapiro`), (4) test execution, (5) markdown interpretation. This pattern makes your statistical reasoning auditable and reproducible — critical when sharing analysis with teams.$escape$,
  $escape$from scipy import stats
import numpy as np
from IPython.display import Markdown, display

np.random.seed(42)
group_a = np.random.normal(loc=50, scale=10, size=100)
group_b = np.random.normal(loc=53, scale=10, size=100)

# Assumption check
_, p_norm = stats.shapiro(group_a)
display(Markdown(f"**Normality check (Shapiro):** p={p_norm:.4f}"))

# Two-sample t-test
t_stat, p_val = stats.ttest_ind(group_a, group_b)
ci = stats.t.interval(0.95, df=len(group_a)-1, loc=np.mean(group_a), scale=stats.sem(group_a))

display(Markdown(f"**t={t_stat:.3f}, p={p_val:.4f}**\n\n95% CI for Group A mean: ({ci[0]:.2f}, {ci[1]:.2f})"))$escape$,
  $escape$python$escape$,
