INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f4ee1f14-7561-4d1e-9883-49a6767eb7e8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Jupyter Notebooks — Version Your Datasets With Cell-Level DVC Tracking$escape$,
  $escape$Every notebook checkpoint saves code state, but the DataFrame you trained on vanishes the moment you overwrite the variable. DVC (Data Version Control) integrates directly into Jupyter cells to hash and track dataset snapshots alongside your .ipynb file.

Install with `%pip install dvc`. Then use `%%capture` and shell magics to version data without leaving the notebook. Each `dvc add` hashes your dataset file and creates a `.dvc` pointer file that Git tracks instead of the raw data. When you `dvc checkout` a prior commit, the exact dataset is restored.

The key insight: pair `%store` or `%%writefile` with DVC to snapshot intermediate DataFrames. Export a filtered DataFrame to Parquet mid-notebook, `!dvc add` it, and commit. Now `git log --oneline` shows model code changes and `dvc diff` shows which dataset version each experiment used. Tag notebook checkpoints with `!git tag exp-v3` so you can reproduce any cell output by restoring both code and data state together. No more 'which CSV did that F1 score come from?'$escape$,
  $escape$import pandas as pd

# After your data cleaning cells:
df_clean.to_parquet("data/train_v2.parquet")

# Version the dataset from inside the notebook
!dvc add data/train_v2.parquet
!git add data/train_v2.parquet.dvc data/.gitignore
!git commit -m "dataset: v2 after outlier removal"
!git tag exp-v2-clean

# Later, restore this exact dataset in any notebook:
# !git checkout exp-v2-clean
# !dvc checkout
df_restored = pd.read_parquet("data/train_v2.parquet")$escape$,
  $escape$python$escape$,
